from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismGetConfigNode(BaseNode):
    name = "Prism: Get Config"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("category", "string", widget_type="text", default="globals")
        self.add_input("key", "string", widget_type="text", default="")
        self.add_input("config_scope", "string", widget_type="dropdown", options=["user","project","shared"], default="user")
        self.add_output("value", "any")
        self.add_output("found", "bool")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        cat = inputs.get('category') or ''
        key = inputs.get('key') or ''
        scope = inputs.get('config_scope') or 'user'
        if core is None:
            self.log_error("No PrismCore provided.")
            return {'value': None, 'found': False}
        try:
            value = None
            if hasattr(core, 'getConfig'):
                try:
                    value = core.getConfig(cat, key, config=scope)
                except TypeError:
                    value = core.getConfig(cat, key)
            elif hasattr(core, 'configs') and hasattr(core.configs, 'getConfig'):
                value = core.configs.getConfig(cat, key, config=scope)
            found = value is not None
            self.log_info(f"Config[{scope}][{cat}][{key}] = {value!r}")
            return {'value': value, 'found': found}
        except Exception as e:
            self.log_error(f"getConfig failed: {e}")
            return {'value': None, 'found': False}

def register_node():
    return PrismGetConfigNode
